insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2005-04-21','Con fecha 3 de sptiembre de 1999 se presenta en la Nootaría de Mérida la Escritura de Aceptación y Partición de Herencia a fin de que sea ratificada por la Comisión como tutora de Agustín Serrano y una vez hecha la misma ante el Notario de Jaraiz por los hermanos. Cuando la recoja la Notaría la manda, internamente, a Jaraiz. Hay que solicitar ante el Juzgado la aprobación de la misma y luego inscribir Con fecha 9 de septiembre se solicita a Caja Extremadura Certificado del saldo, una vez que hemos recibido el certificado de la pensión por importe de 54.815 pts (orfandad). Estar pendiente y ver si aparecen ingresos por importe de 24.935 pts pues esta pensión, por resolución de 1.09.98 queda extinguida. Le reclaman 49.870 pts (C.Bienestar Social), correspondiente al período de 01.09.98 a 31.10.98. !!!!! Ver cuando se lo retiran. Con fecha de septiembre de 1999 por Acuerdo de la Vicepresidenta se gestiona su ingreso en la Asociación "VERA" de Jaraiz. Estaba concedida la autorización judicial pom Auto de fecha 9 de abril de 1999. Había solicitado ingreso en algún CAMP pero no aconsejan su ingreso debido a la esquizofrenia que padece. Cuando venga la documentación que falta hacer la relación de bienes al Juzgado, comunicar también el ingreso.','2');
