insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2005-04-21','Con fecha 11 de marzo de 2004 se dicta Auto aprobando el Inventario de Bienes. Retraso Intelectual. 51% de Minusvalía. Actualmente trabaja, como Conserje, en el CADEX de Cáceres. Convenio de Inserción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JUANA'and edp.apellido1='CARLOS'and apellido2='CANELO'),'2005-04-21','El día 28 de abril de 2004 se celebran dos juicios en Plasencia donde comparece en calidad de Denunciante, es acompañada por la Secretaria de la Comisión Tutelar y visitando posteriormente su domicilio y trabajadora social. Con fecha 21 de marzo de 2000 se dicta sentencia de Incapacidad, nombrando tutor de la misma a su hermana Gloria por Auto de 20 de julio de 2000. Iniciado porcedimiento de Reintegración de Capacidad se dicta Sentencia con fecha 11 de febrero de 2003 desestimando la demanda y no modificando el régimen de guarda, la curatela. Iniciado procedimiento de remoción se dicta Auto con fecha 7 de julio de 2003 nombrando tutor a la Comisión Tutelar por enfrentamiento entre las hermanas. La curatela no se extiende a los actos de administración y gobierno de su persona, sólo la administración de sus bienes. Remoción cargo anterior tutor. Pedir testimonio al Juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2005-04-21','El Auto Declarando el desamparo junto con el expediente nos lo remite Gabinete Jurídico en noviembre de 2004. La sentencia de incapacidad declara la incapacidad parcial por lo que respecta a la esfera personal.... Intervenir el curador en actos de decisión en materia de admón de fármacos y viajes que superen los 50 Km desde la localidad de su residencia. Con plena capacidad para adminstrar sus bienes y para los actos de gobierno de su persona.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='PRIOR'and apellido2='ARIAS'),'2005-10-25','Sentencia dictada por el Juzgado de Primera Instancia de Llerena en el procedimiento 92/05 por la que se acuerda la incapacitación total y se acuerda la prórroga de la patria potestad de sus padres, D. Telesforo Prior y Dª Matilde Arias','2');
